// ─── Follow-up Form ───────────────────────────────────────────────────────────
function FollowUpForm({ sentLog, onSent }) {
  const [mode, setMode] = useState("select"); // select | manual
  const [selectedIdx, setSelectedIdx] = useState("");
  const [form, setForm] = useState({
    hrEmail: "", hrName: "", company: "", role: "",
    originalDate: "", customNote: "",
    originalMessageId: "", originalSubject: "",
  });
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState(null);

  const handle = (e) => {
    setForm((p) => ({ ...p, [e.target.name]: e.target.value }));
    if (status) setStatus(null);
  };

  const selectApplication = (idx) => {
    setSelectedIdx(idx);
    if (idx === "") return;
    const entry = sentLog[parseInt(idx)];
    setForm({
      hrEmail: entry.hrEmail || "",
      hrName: entry.hrName || "",
      company: entry.company || "",
      role: entry.role || "",
      originalDate: entry.time || "",
      customNote: "",
      originalMessageId: entry.messageId || "",
      originalSubject: entry.subject || "",
    });
    if (status) setStatus(null);
  };

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatus(null);
    try {
      const res = await axios.post(`${API}/api/send-followup`, form);
      setStatus({ type: "success", text: res.data.message });
      onSent({
        type: "followup",
        company: form.company,
        role: form.role,
        email: form.hrEmail,
        time: new Date().toLocaleString(),
        messageId: res.data.messageId,
        subject: form.originalSubject,
        hrName: form.hrName,
        hrEmail: form.hrEmail,
      });
      setForm({ hrEmail: "", hrName: "", company: "", role: "", originalDate: "", customNote: "", originalMessageId: "", originalSubject: "" });
      setSelectedIdx("");
    } catch (err) {
      setStatus({ type: "error", text: err.response?.data?.message || "Failed to send." });
    } finally {
      setLoading(false);
    }
  };

  const valid = form.hrEmail && form.company;
  const appliedEntries = sentLog.filter((e) => e.type === "application");

  return (
    <form className="mailer-form" onSubmit={submit} noValidate>

      {/* Quick-fill from sent applications */}
      {appliedEntries.length > 0 && (
        <div className="form-group">
          <label className="form-label" htmlFor="selectApp">
            <span className="lbadge lbadge-green">Quick Fill</span>
            Select from sent applications
          </label>
          <select
            id="selectApp" className="form-input form-select"
            value={selectedIdx} onChange={(e) => selectApplication(e.target.value)}
            disabled={loading}
          >
            <option value="">— Choose a previous application —</option>
            {sentLog.map((e, i) =>
              e.type === "application" ? (
                <option key={i} value={i}>
                  {e.company}{e.role ? ` · ${e.role}` : ""} ({e.email}) — {e.time}
                </option>
              ) : null
            )}
          </select>
        </div>
      )}

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-hrEmail">
            <span className="lbadge">Required</span> HR Email
          </label>
          <input id="fu-hrEmail" name="hrEmail" type="email" value={form.hrEmail}
            onChange={handle} placeholder="recruiter@company.com"
            className="form-input" required disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-hrName">
            <span className="lbadge lbadge-opt">Optional</span> HR Name
          </label>
          <input id="fu-hrName" name="hrName" type="text" value={form.hrName}
            onChange={handle} placeholder="e.g. Priya Sharma"
            className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-company">
            <span className="lbadge">Required</span> Company
          </label>
          <input id="fu-company" name="company" type="text" value={form.company}
            onChange={handle} placeholder="Company Name"
            className="form-input" required disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-role">
            <span className="lbadge lbadge-opt">Optional</span> Role
          </label>
          <input id="fu-role" name="role" type="text" value={form.role}
            onChange={handle} placeholder="e.g. Senior Full Stack Developer"
            className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-date">
            <span className="lbadge lbadge-opt">Optional</span> Original Application Date
          </label>
          <input id="fu-date" name="originalDate" type="text" value={form.originalDate}
            onChange={handle} placeholder="e.g. 25 May 2026"
            className="form-input" disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-msgid">
            <span className="lbadge lbadge-opt">Optional</span> Original Message ID
            <span className="label-hint">Auto-filled if you used Quick Fill — enables email threading</span>
          </label>
          <input id="fu-msgid" name="originalMessageId" type="text" value={form.originalMessageId}
            onChange={handle} placeholder="<msgid@gmail.com>"
            className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-group">
        <label className="form-label" htmlFor="fu-note">
          <span className="lbadge lbadge-opt">Optional</span> Custom Note
        </label>
        <textarea id="fu-note" name="customNote" value={form.customNote}
          onChange={handle}
          placeholder="e.g. I wanted to reiterate my excitement about this opportunity. I recently..."
          className="form-textarea" rows={3} disabled={loading} />
      </div>

      {/* Thread info */}
      {form.originalMessageId && (
        <div className="thread-notice">
          <span className="thread-icon">🧵</span>
          <span>This follow-up will be sent <strong>in the same email thread</strong> as the original application.</span>
        </div>
      )}

      {status && (
        <div className={`alert alert-${status.type}`} role="alert">
          <span className="alert-icon">{status.type === "success" ? "✓" : "✕"}</span>
          <span>{status.text}</span>
        </div>
      )}

      <div className="form-footer">
        <button type="submit" className={`btn-followup ${loading ? "loading" : ""}`} disabled={loading || !valid}>
          {loading ? <><span className="spinner" /> Sending Follow-up…</> : <><span className="btn-arrow">↑</span> Send Follow-up</>}
        </button>
        <button type="button" className="btn-ghost" disabled={loading}
          onClick={() => { setForm({ hrEmail: "", hrName: "", company: "", role: "", originalDate: "", customNote: "", originalMessageId: "", originalSubject: "" }); setSelectedIdx(""); setStatus(null); }}>
          Clear
        </button>
      </div>
    </form>
  );
}

